-- Phase 3 Stage 6 (#44): Bronze domain sanity checks
-- Parameter: :batch_id

WITH reference_codes AS (
  SELECT CODE_SET_NAME, CODE_VALUE
  FROM FRAUDLENS.BRONZE.BRONZE_REFERENCE_DATA_CATALOG
  WHERE INGESTION_BATCH_ID = :batch_id
),
