  UNION ALL
  SELECT 'reference_domain' AS check_type, 'branch_location' AS dataset_name, 'country_code' AS column_name, 'country_code' AS rule_name, COUNT_IF(src.COUNTRY_CODE IS NOT NULL AND TRIM(src.COUNTRY_CODE::STRING) <> '' AND ref.CODE_VALUE IS NULL) AS failed_count, COUNT(*) AS row_count FROM FRAUDLENS.BRONZE.BRONZE_BRANCH_LOCATION src LEFT JOIN reference_codes ref ON ref.CODE_SET_NAME = 'country_code' AND ref.CODE_VALUE = src.COUNTRY_CODE WHERE src.INGESTION_BATCH_ID = :batch_id
