  UNION ALL
  SELECT 'reference_domain' AS check_type, 'decision_record' AS dataset_name, 'decision_type' AS column_name, 'decision_type' AS rule_name, COUNT_IF(src.DECISION_TYPE IS NOT NULL AND TRIM(src.DECISION_TYPE::STRING) <> '' AND ref.CODE_VALUE IS NULL) AS failed_count, COUNT(*) AS row_count FROM FRAUDLENS.BRONZE.BRONZE_DECISION_RECORD src LEFT JOIN reference_codes ref ON ref.CODE_SET_NAME = 'decision_type' AND ref.CODE_VALUE = src.DECISION_TYPE WHERE src.INGESTION_BATCH_ID = :batch_id
  UNION ALL
  SELECT 'reference_domain' AS check_type, 'decision_record' AS dataset_name, 'decision_status' AS column_name, 'decision_status' AS rule_name, COUNT_IF(src.DECISION_STATUS IS NOT NULL AND TRIM(src.DECISION_STATUS::STRING) <> '' AND ref.CODE_VALUE IS NULL) AS failed_count, COUNT(*) AS row_count FROM FRAUDLENS.BRONZE.BRONZE_DECISION_RECORD src LEFT JOIN reference_codes ref ON ref.CODE_SET_NAME = 'decision_status' AND ref.CODE_VALUE = src.DECISION_STATUS WHERE src.INGESTION_BATCH_ID = :batch_id
  UNION ALL
  SELECT 'reference_domain' AS check_type, 'decision_record' AS dataset_name, 'decision_reason_code' AS column_name, 'decision_reason_code' AS rule_name, COUNT_IF(src.DECISION_REASON_CODE IS NOT NULL AND TRIM(src.DECISION_REASON_CODE::STRING) <> '' AND ref.CODE_VALUE IS NULL) AS failed_count, COUNT(*) AS row_count FROM FRAUDLENS.BRONZE.BRONZE_DECISION_RECORD src LEFT JOIN reference_codes ref ON ref.CODE_SET_NAME = 'decision_reason_code' AND ref.CODE_VALUE = src.DECISION_REASON_CODE WHERE src.INGESTION_BATCH_ID = :batch_id
