  UNION ALL
  SELECT 'reference_domain' AS check_type, 'case_disposition' AS dataset_name, 'disposition_code' AS column_name, 'disposition_code' AS rule_name, COUNT_IF(src.DISPOSITION_CODE IS NOT NULL AND TRIM(src.DISPOSITION_CODE::STRING) <> '' AND ref.CODE_VALUE IS NULL) AS failed_count, COUNT(*) AS row_count FROM FRAUDLENS.BRONZE.BRONZE_CASE_DISPOSITION src LEFT JOIN reference_codes ref ON ref.CODE_SET_NAME = 'disposition_code' AND ref.CODE_VALUE = src.DISPOSITION_CODE WHERE src.INGESTION_BATCH_ID = :batch_id
