  SELECT 'numeric_sanity' AS check_type, 'payment_instruction' AS dataset_name, 'instructed_amount' AS column_name, 'gt_0' AS rule_name, COUNT_IF(src.INSTRUCTED_AMOUNT IS NOT NULL AND NOT (src.INSTRUCTED_AMOUNT > 0)) AS failed_count, COUNT(*) AS row_count FROM FRAUDLENS.BRONZE.BRONZE_PAYMENT_INSTRUCTION src WHERE src.INGESTION_BATCH_ID = :batch_id
