  SELECT 'numeric_sanity' AS check_type, 'payment_transaction' AS dataset_name, 'booking_amount' AS column_name, 'gteq_0' AS rule_name, COUNT_IF(src.BOOKING_AMOUNT IS NOT NULL AND NOT (src.BOOKING_AMOUNT >= 0)) AS failed_count, COUNT(*) AS row_count FROM FRAUDLENS.BRONZE.BRONZE_PAYMENT_TRANSACTION src WHERE src.INGESTION_BATCH_ID = :batch_id
