  SELECT 'numeric_sanity' AS check_type, 'case_disposition' AS dataset_name, 'loss_amount' AS column_name, 'gteq_0' AS rule_name, COUNT_IF(src.LOSS_AMOUNT IS NOT NULL AND NOT (src.LOSS_AMOUNT >= 0)) AS failed_count, COUNT(*) AS row_count FROM FRAUDLENS.BRONZE.BRONZE_CASE_DISPOSITION src WHERE src.INGESTION_BATCH_ID = :batch_id
  UNION ALL
  SELECT 'numeric_sanity' AS check_type, 'case_disposition' AS dataset_name, 'recovered_amount' AS column_name, 'gteq_0' AS rule_name, COUNT_IF(src.RECOVERED_AMOUNT IS NOT NULL AND NOT (src.RECOVERED_AMOUNT >= 0)) AS failed_count, COUNT(*) AS row_count FROM FRAUDLENS.BRONZE.BRONZE_CASE_DISPOSITION src WHERE src.INGESTION_BATCH_ID = :batch_id
  UNION ALL
  SELECT 'numeric_sanity' AS check_type, 'case_disposition' AS dataset_name, 'write_off_amount' AS column_name, 'gteq_0' AS rule_name, COUNT_IF(src.WRITE_OFF_AMOUNT IS NOT NULL AND NOT (src.WRITE_OFF_AMOUNT >= 0)) AS failed_count, COUNT(*) AS row_count FROM FRAUDLENS.BRONZE.BRONZE_CASE_DISPOSITION src WHERE src.INGESTION_BATCH_ID = :batch_id
)
SELECT
  check_type,
  dataset_name,
  column_name,
  rule_name,
  row_count,
  failed_count,
  CASE WHEN failed_count = 0 THEN 'pass' ELSE 'fail' END AS check_status
FROM domain_checks
ORDER BY check_type, dataset_name, column_name;
